        topicos: [
          { titulo: 'Arquitetura do projeto', descricao: 'Estrutura: server.ts (entry), routes/tarefas.ts (rotas), schemas/tarefa.ts (validação), middlewares/ (logger, error, auth). Separação clara de responsabilidades. Dados em memória (array) para simplicidade.', exemplo: 'src/\\n  server.ts\\n  routes/tarefas.ts\\n  schemas/tarefa.ts\\n  middlewares/logger.ts\\n  middlewares/error.ts' },
          { titulo: 'Integração frontend-backend', descricao: 'Frontend React faz fetch para backend: fetch("http://localhost:3000/api/tarefas"). Configure CORS. Use useEffect + useState para buscar dados. Para criar: POST com JSON body. Use variável de ambiente VITE_API_URL para URL do backend.', exemplo: 'const API = import.meta.env.VITE_API_URL || "http://localhost:3000/api";\\nfetch(\`\${API}/tarefas\`).then(r => r.json()).then(setTarefas);' }
        ],
        exercicio: 'Complete a API de tarefas CRUD + validação. Conecte com o frontend React existente (substitua dados mock por API).',
        codigoInicial: '// routes/tarefas.ts\\nimport { Router, Request, Response } from "express";\\nimport { z } from "zod";\\nconst router = Router();\\ninterface Tarefa { id: number; titulo: string; concluida: boolean; criadaEm: Date; }\\nlet tarefas: Tarefa[] = [];\\nconst TarefaSchema = z.object({ titulo: z.string().min(1, "Título obrigatório"), concluida: z.boolean().optional().default(false) });\\nrouter.get("/", (req, res) => res.json(tarefas));\\nrouter.post("/", (req, res) => {\\n  const dados = TarefaSchema.parse(req.body);\\n  const nova: Tarefa = { id: Date.now(), ...dados, criadaEm: new Date() };\\n  tarefas.push(nova);\\n  res.status(201).json(nova);\\n});\\nexport default router;',
        codigoSolucao: '// Adicione PUT e DELETE\\nrouter.put("/:id", (req, res) => {\\n  const index = tarefas.findIndex(t => t.id === Number(req.params.id));\\n  if (index === -1) return res.status(404).json({ error: "Não encontrada" });\\n  const dados = TarefaSchema.partial().parse(req.body);\\n  tarefas[index] = { ...tarefas[index], ...dados };\\n  res.json(tarefas[index]);\\n});\\nrouter.delete("/:id", (req, res) => {\\n  const index = tarefas.findIndex(t => t.id === Number(req.params.id));\\n  if (index === -1) return res.status(404).json({ error: "Não encontrada" });\\n  tarefas.splice(index, 1);\\n  res.status(204).end();\\n});'
