          { titulo: 'Refatorando login com bcrypt', descricao: 'No register: hash = await bcrypt.hash(senha, 10); user = { ...dados, senha: hash }. No login: const user = await findUser(email); const match = await bcrypt.compare(senha, user.senha). Se match, gera token.', exemplo: '// Register\\nconst senhaHash = await bcrypt.hash(senha, 10);\\nconst user = { id: Date.now(), nome, email, senha: senhaHash };\\n\\n// Login\\nconst user = users.find(u => u.email === email);\\nif (!user || !(await bcrypt.compare(senha, user.senha))) {\\n  return res.status(401).json({ error: "Credenciais inválidas" });\\n}' },
          { titulo: 'Variáveis de ambiente com dotenv', descricao: 'npm install dotenv. Crie .env com JWT_SECRET, PORT, DATABASE_URL. No server.ts: import "dotenv/config". .env nunca versionado! .env.example para documentar variáveis.', exemplo: '# .env\\nJWT_SECRET=seu-segredo-super-seguro\\nPORT=3000\\nDATABASE_URL="file:./dev.db"\\n\\n// server.ts\\nimport "dotenv/config";\\nconst PORT = process.env.PORT || 3000;' },
          { titulo: 'Boas práticas de segurança', descricao: 'Nunca retorne a senha (hash ou não) nas respostas. Use HTTPS em produção. Valide entrada com Zod. Limite taxas de login (rate limiting). Use Helmet para headers de segurança: app.use(helmet()).', exemplo: 'import helmet from "helmet";\\napp.use(helmet());\\napp.use(cors());\\napp.use(express.json({ limit: "10kb" })); // limite de body' }
