        codigoInicial: '// Adicione bcrypt ao register:\\nimport bcrypt from "bcrypt";\\nrouter.post("/register", async (req, res) => {\\n  const { nome, email, senha } = req.body;\\n  const senhaHash = await bcrypt.hash(senha, 10);\\n  const user = { id: Date.now(), nome, email, senha: senhaHash };\\n  users.push(user);\\n  res.status(201).json({ id: user.id, nome, email });\\n});',
        codigoSolucao: '// Login com bcrypt\\nrouter.post("/login", async (req, res) => {\\n  const { email, senha } = req.body;\\n  const user = users.find(u => u.email === email);\\n  if (!user) return res.status(401).json({ error: "Credenciais inválidas" });\\n  const match = await bcrypt.compare(senha, user.senha);\\n  if (!match) return res.status(401).json({ error: "Credenciais inválidas" });\\n  const token = jwt.sign({ userId: user.id }, process.env.JWT_SECRET || "dev", { expiresIn: "7d" });\\n  res.json({ token, user: { id: user.id, nome: user.nome, email: user.email } });\\n});'
