        codigoInicial: '// tests/auth.test.ts\\nimport request from "supertest";\\nimport { app } from "../server";\\n\\ndescribe("Auth API", () => {\\n  it("POST /api/auth/register - cria usuário", async () => {\\n    const res = await request(app)\\n      .post("/api/auth/register")\\n      .send({ nome: "Teste", email: "test@email.com", senha: "Senha123" });\\n    expect(res.status).toBe(201);\\n    expect(res.body).toHaveProperty("token");\\n  });\\n\\n  it("POST /api/auth/register - email duplicado", async () => {\\n    const res = await request(app)\\n      .post("/api/auth/register")\\n      .send({ nome: "Teste", email: "test@email.com", senha: "Senha123" });\\n    expect(res.status).toBe(409);\\n  });\\n\\n  it("POST /api/auth/login - sucesso", async () => {\\n    const res = await request(app)\\n      .post("/api/auth/login")\\n      .send({ email: "test@email.com", senha: "Senha123" });\\n    expect(res.status).toBe(200);\\n    expect(res.body).toHaveProperty("token");\\n  });\\n});',
