        codigoInicial: '// client/src/contexts/AuthContext.tsx\\nimport { createContext, useContext, useState, useEffect, ReactNode } from "react";\\nimport api from "../api";\\n\\ninterface User { id: number; nome: string; email: string; }\\ninterface AuthContextType {\\n  user: User | null;\\n  token: string | null;\\n  isAuthenticated: boolean;\\n  login: (email: string, senha: string) => Promise<void>;\\n  register: (nome: string, email: string, senha: string) => Promise<void>;\\n  logout: () => void;\\n}\\nconst AuthContext = createContext<AuthContextType | null>(null);',
        codigoSolucao: 'export function AuthProvider({ children }: { children: ReactNode }) {\\n  const [user, setUser] = useState<User | null>(null);\\n  const [token, setToken] = useState<string | null>(localStorage.getItem("token"));\\n\\n  useEffect(() => {\\n    if (token) { api.get("/auth/perfil").then(r => setUser(r.data)).catch(() => logout()); }\\n  }, [token]);\\n\\n  const login = async (email: string, senha: string) => {\\n    const { data } = await api.post("/auth/login", { email, senha });\\n    setToken(data.token);\\n    setUser(data.user);\\n    localStorage.setItem("token", data.token);\\n  };\\n\\n  const register = async (nome: string, email: string, senha: string) => {\\n    const { data } = await api.post("/auth/register", { nome, email, senha });\\n    setToken(data.token);\\n    setUser(data.user);\\n    localStorage.setItem("token", data.token);\\n  };\\n\\n  const logout = () => {\\n    setToken(null);\\n    setUser(null);\\n    localStorage.removeItem("token");\\n  };\\n\\n  return (\\n    <AuthContext.Provider value={{ user, token, isAuthenticated: !!token, login, register, logout }}>\\n      {children}\\n    </AuthContext.Provider>\\n  );\\n}\\n\\nexport const useAuth = () => {\\n  const ctx = useContext(AuthContext);\\n  if (!ctx) throw new Error("useAuth must be used within AuthProvider");\\n  return ctx;\\n};'
